import{j as e,m as n,r as d}from"./index-Bblu6sUX.js";import{C as m,a as p}from"./chevron-up-BnIbu6Nx.js";function h({section:i,lightMode:t}){const[a,s]=d.useState(!1),o=t?"#111827":"#F9FAFB",l=t?"#6B7280":"#9CA3AF",r=t?"#E5E7EB":"#1A1A1A";return e.jsxs("div",{className:"bis-section-card mb-3 overflow-hidden rounded-[24px]",style:{borderColor:r},children:[e.jsxs("button",{onClick:()=>s(c=>!c),className:`w-full flex items-center justify-between cursor-pointer px-6 py-4 text-left transition-colors ${t?"hover:bg-gray-50/70":"hover:bg-white/[0.02]"}`,children:[e.jsx("span",{className:"font-semibold text-sm",style:{color:o},children:i.title}),a?e.jsx(m,{className:"w-4 h-4 flex-shrink-0 text-gray-500"}):e.jsx(p,{className:"w-4 h-4 flex-shrink-0 text-gray-500"})]}),a&&e.jsx(n.div,{initial:{opacity:0,height:0},animate:{opacity:1,height:"auto"},exit:{opacity:0,height:0},className:"px-6 pb-5 text-sm leading-relaxed space-y-3",style:{color:l,borderTop:`1px solid ${r}`},children:e.jsx("div",{className:"pt-4",children:i.content})})]})}const u=[{id:"regime",title:"1. Regime Detection Methodology",content:e.jsxs("div",{className:"space-y-3",children:[e.jsx("p",{children:"Quantus classifies market conditions into five regimes before any signal is generated. Regime determines which models are active, which strategies are recommended, and how position sizing is calibrated."}),e.jsx("ul",{className:"space-y-2 pl-4",children:[["Strong Uptrend (>15% 30d gain)","Momentum dominant. Mean reversion suppressed. Trend-following strategies active."],["Uptrend (5–15% 30d gain)","Moderate momentum. Some reversion opportunity. Both momentum and value signals active."],["Sideways (±5% 30d)","Range-bound. Mean reversion active. Options strategies gain priority."],["Downtrend (<−15% 30d)","Bearish momentum. Defensive posture. Pairs trading and short considerations."],["High Volatility (annualised vol >30%)","Regime-agnostic. Position sizing reduced by 40%. All risk metrics take precedence."]].map(([i,t])=>e.jsxs("li",{children:[e.jsxs("span",{className:"font-semibold text-blue-400",children:[i,":"]})," ",t]},i))}),e.jsx("p",{className:"text-xs opacity-60",children:"Data: 30-day price return (Yahoo Finance, live), annualised volatility (60-day rolling standard deviation of daily returns). Regime is recalculated on every report generation."})]})},{id:"models",title:"2. The 12 Quantitative Models",content:e.jsx("div",{className:"space-y-4",children:[{n:"1. ARIMA (AutoRegressive Integrated Moving Average)",d:"Captures linear time-series dependencies. Weight: 20% in ensemble. Best suited for stable, mean-reverting price series. Limitation: assumes stationarity — degrades in trending regimes.",t:"Time series analysis"},{n:"2. Prophet (Facebook/Meta)",d:"Handles seasonality and calendar effects automatically. Weight: 35%. Best suited for assets with strong weekly or annual seasonality (e.g. commodities, retail equities). Limitation: struggles with structural breaks.",t:"Seasonality-aware forecasting"},{n:"3. LSTM (Long Short-Term Memory)",d:"Learns non-linear temporal relationships. Weight: 45% — highest due to superior regime adaptability. Trained on 10 years of daily OHLCV data. Limitation: computationally intensive; requires GPU inference for real-time use.",t:"Deep learning"},{n:"4. Mean Reversion (Ornstein-Uhlenbeck)",d:"Models the speed and magnitude of reversion to a long-run mean. Outputs: half-life in days, Z-score, entry and exit levels. Calibrated on 252-day rolling window.",t:"Statistical arbitrage"},{n:"5. Sentiment Composite",d:"Credibility-weighted combination of Grok/X firehose (50%), Reddit NLP (25%), NewsAPI (25%). Campaign detection algorithm down-weights coordinated inauthentic activity.",t:"Alternative data"},{n:"6. Portfolio Optimization (Mean-Variance)",d:"Computes efficient frontier allocation given current holdings. Outputs: optimal weight, Sharpe improvement, correlation impact. Relies on 60-day covariance matrix.",t:"Portfolio theory"},{n:"7. SHAP Feature Importance",d:"Explains which sub-signals contributed most to the final recommendation using SHapley Additive exPlanations. Presented as a ranked waterfall chart. Auditable by design.",t:"Model explainability"},{n:"8. High-Frequency Signal",d:"Intraday momentum derived from VWAP deviation, bid-ask spread dynamics, and tick-level volume divergence. Useful for timing entry/exit within a day.",t:"Microstructure"},{n:"9. VaR & Risk Management",d:"Historical Simulation VaR (99%, 1-day), Expected Shortfall, and three macro stress scenarios (2008 GFC −45%, COVID −30%, Inflation 2022 −35%). All figures beta-scaled to the specific ticker.",t:"Risk management"},{n:"10. Options Pricing & Greeks",d:"Black-Scholes pricing, full Greeks surface (Delta, Gamma, Vega, Theta, Rho), IV Rank vs 52-week range, and implied 30-day move. Available for liquid equity options.",t:"Derivatives"},{n:"11. Reinforcement Learning Agent",d:"PPO (Proximal Policy Optimisation) agent trained on 10 years of historical data with transaction cost simulation. Outputs current allocation recommendation. Not used as primary signal — advisory only.",t:"AI agent"},{n:"12. Factor Investing (Barra-style)",d:"Decomposes returns into Value, Momentum, Quality, Low-Volatility, and Size factors. Shows which factors explain recent performance and whether the current regime favours each.",t:"Factor analysis"}].map(i=>e.jsxs("div",{className:"border-l-2 pl-3",style:{borderColor:"#2D3748"},children:[e.jsx("div",{className:"font-semibold text-xs mb-0.5",children:i.n}),e.jsx("div",{className:"text-xs opacity-70 mb-1 uppercase tracking-wider",children:i.t}),e.jsx("div",{children:i.d})]},i.n))})},{id:"ensemble",title:"3. Model Ensemble Weighting",content:e.jsxs("div",{className:"space-y-3",children:[e.jsx("p",{children:"Meridian v2.4 weights the three core forecasting models as follows: LSTM 45%, Prophet 35%, ARIMA 20%. Weights were determined by walk-forward backtesting across 2018–2024 on 400+ equities, 15 crypto assets, and 8 commodity futures."}),e.jsx("p",{children:`When all three models agree directionally, the confidence score's "model ensemble agreement" sub-component receives its full 15 points. When two of three agree, it receives 10. Full disagreement contributes 5, and a data_caveat is appended noting the divergence.`}),e.jsx("p",{children:"Regime context modulates weights in real time: LSTM weight increases to 55% in trending regimes (where non-linearity adds more signal); ARIMA weight increases to 30% in sideways regimes where linear AR structure is more appropriate."})]})},{id:"grok",title:"4. Grok API Privileged Firehose Access",content:e.jsxs("div",{className:"space-y-3",children:[e.jsx("p",{children:"Quantus accesses the Grok API's full-fidelity X (Twitter) firehose — not the Standard API's filtered, sampled subset. This means every public post is processed in real time, including posts from verified institutional accounts that are most predictive of market direction."}),e.jsxs("p",{children:[e.jsx("strong",{children:"Credibility weighting:"}),' Posts from accounts with "Verified Organisation" status contribute 3× the weight of unverified accounts. Accounts with a finance-industry bio verified by Grok contribute 2×. Anonymous accounts contribute 1×.']}),e.jsxs("p",{children:[e.jsx("strong",{children:"Campaign detection:"})," Quantus uses coordinated pattern detection (post timing, cross-account linguistic similarity) to identify and down-weight potential market manipulation campaigns. When detected, a data_caveat is appended."]}),e.jsx("p",{className:"text-xs opacity-60",children:"Limitation: Grok API is a Tier C data source (medium credibility) for final signal construction. Sentiment is advisory — it cannot override Tier A sources (SEC EDGAR, FRED)."})]})},{id:"altdata",title:"5. Alternative Data Sources & Credibility Tiers",content:e.jsxs("div",{className:"space-y-3",children:[e.jsxs("table",{className:"w-full text-xs",children:[e.jsx("thead",{children:e.jsxs("tr",{className:"text-left border-b",style:{borderColor:"#374151"},children:[e.jsx("th",{className:"pb-2 font-semibold",children:"Tier"}),e.jsx("th",{className:"pb-2 font-semibold",children:"Sources"}),e.jsx("th",{className:"pb-2 font-semibold",children:"Credibility"}),e.jsx("th",{className:"pb-2 font-semibold",children:"Use"})]})}),e.jsx("tbody",{className:"space-y-2",children:[["A","SEC EDGAR, FRED, CBOE","Highest","Fundamental anchors — override lower tiers"],["B","Yahoo Finance / yfinance, Financial Modeling Prep","High","Price, earnings, fundamentals"],["C","Grok/X, Reddit, NewsAPI","Medium","Sentiment only — never standalone signal"]].map(([i,t,a,s])=>e.jsxs("tr",{className:"border-b",style:{borderColor:"#1A1A1A"},children:[e.jsxs("td",{className:"py-2 font-bold",style:{color:i==="A"?"#10B981":i==="B"?"#3B82F6":"#9CA3AF"},children:["Tier ",i]}),e.jsx("td",{className:"py-2",children:t}),e.jsx("td",{className:"py-2",children:a}),e.jsx("td",{className:"py-2",children:s})]},i))})]}),e.jsx("p",{children:"No Tier C source can produce a BUY or STRONG BUY signal in isolation. All sentiment signals require corroboration from at least one Tier A or Tier B source to contribute to the final recommendation."})]})},{id:"confidence",title:"6. Confidence Score Composition",content:e.jsxs("div",{className:"space-y-3",children:[e.jsx("p",{children:"The confidence score (0–100) is a weighted composite of seven sub-signals, each calibrated to their maximum attainable value:"}),e.jsx("div",{className:"space-y-2",children:[["Momentum (RSI, MACD, regime alignment)","20%"],["Sentiment (Grok/X, Reddit, News credibility-weighted)","15%"],["Regime Alignment (signal consistent with current regime)","15%"],["Model Ensemble Agreement (ARIMA + Prophet + LSTM)","15%"],["Alternative Data (13F, insider, IV rank)","15%"],["Macro Context (Fed rate, yield curve, VIX, credit spreads)","10%"],["Data Quality (freshness, completeness, circuit breakers)","10%"]].map(([i,t])=>e.jsxs("div",{className:"flex items-start justify-between gap-4",children:[e.jsx("span",{className:"flex-1",children:i}),e.jsx("span",{className:"font-mono font-bold flex-shrink-0",style:{color:"#6366F1"},children:t})]},i))}),e.jsx("p",{className:"text-xs opacity-60",children:"When a circuit breaker activates (data source unavailable), the corresponding sub-weight is reduced proportionally and a data_caveat is appended. A score of 60+ with a data quality score of 5/10 should be interpreted differently from 60+ with data quality 9/10."})]})},{id:"knowledge-graph",title:"7. Knowledge Graph & Cross-Ticker Intelligence",content:e.jsxs("div",{className:"space-y-3",children:[e.jsx("p",{children:"Quantus maintains a supply chain and competitive relationship graph across the equity universe. When a material event affects one node (e.g. a TSMC capacity constraint), all downstream nodes (NVIDIA, Apple, Qualcomm) receive a cross-ticker alert within the same report cycle."}),e.jsx("p",{children:"The graph is constructed from SEC EDGAR supplier disclosures, earnings call transcript NLP, and 13F institutional holding overlaps. Relationships are weighted by revenue exposure — a company where Supplier X represents 40% of COGS receives a higher-priority alert than one at 5%."}),e.jsx("p",{children:"Cross-ticker alerts appear as amber banners on the Welcome Card and are included in the daily digest email. They do not automatically change the primary signal — they are advisory context."})]})},{id:"shared",title:"8. Shared Report Model & Meridian Versioning",content:e.jsxs("div",{className:"space-y-3",children:[e.jsx("p",{children:"Every report generated by Quantus is stored in Redis with a 96-hour TTL and immediately available to all researchers requesting the same ticker. This is the Shared Intelligence Model — one expensive computation, shared across the entire community."}),e.jsxs("p",{children:[e.jsx("strong",{children:"Meridian v2.4"})," is the current production prompt version. Meridian v2.3 is available in the Historical Archive for comparison. Earlier versions (Atlas) had lower directional accuracy (61% vs Meridian's 67%) and are marked in the archive. Version identifiers are immutable and cryptographically bound to each report_id."]}),e.jsxs("p",{children:[e.jsx("strong",{children:"Cache invalidation triggers:"})," Equity price move ",">","5%, crypto price move ",">","8%, FRED macro data update, FMP earnings release, or Polygon options flow spike. Manual invalidation available to Institutional clients."]})]})},{id:"feedback",title:"9. User Feedback & Signal Quality Improvement",content:e.jsxs("div",{className:"space-y-3",children:[e.jsx("p",{children:"Every Deep Dive module and narrative section includes 👍 / 👎 feedback buttons. Feedback is anonymised and aggregated — your individual rating is never exposed to other users."}),e.jsx("p",{children:"Feedback signals feed into two improvement loops: (1) prompt weighting — sections receiving systematic 👎 are flagged for human review and prompt refinement in the next Meridian version; (2) confidence calibration — when 👍/👎 patterns diverge from actual price outcomes, the corresponding sub-signal weights are adjusted in the next calibration cycle."}),e.jsx("p",{children:"Institutional clients can annotate reports with private notes. These annotations are never shared with other users or used in aggregate feedback loops."})]})},{id:"compliance",title:"10. Regulatory Compliance by Jurisdiction",content:e.jsxs("div",{className:"space-y-3",children:[e.jsxs("table",{className:"w-full text-xs",children:[e.jsx("thead",{children:e.jsxs("tr",{className:"text-left border-b",style:{borderColor:"#374151"},children:[e.jsx("th",{className:"pb-2 font-semibold",children:"Jurisdiction"}),e.jsx("th",{className:"pb-2 font-semibold",children:"Disclaimer Standard"}),e.jsx("th",{className:"pb-2 font-semibold",children:"Notes"})]})}),e.jsx("tbody",{children:[["United States","Not investment advice. Not a registered investment adviser.","SEC Rule 202(a)(11) research carve-out applies."],["United Kingdom","Financial promotion approved for professional investors. FCA consideration.","FSMA 2000 s.21 applies. Retail distribution requires FCA authorisation."],["European Union","MiFID II Article 24 disclosure. Not PRIIP-compliant for retail.","Available to elective professional clients under MiFID II."],["Global / Other","For informational purposes only. Not investment advice.","Institutional use presumed outside above jurisdictions."]].map(([i,t,a])=>e.jsxs("tr",{className:"border-b",style:{borderColor:"#1A1A1A"},children:[e.jsx("td",{className:"py-2 font-semibold",children:i}),e.jsx("td",{className:"py-2",children:t}),e.jsx("td",{className:"py-2 opacity-60",children:a})]},i))})]}),e.jsx("p",{className:"text-xs opacity-60",children:"Disclaimer text is automatically selected based on the user's jurisdiction setting. Jurisdiction is set at account creation and can be updated in settings. All emails and PDF exports carry the appropriate jurisdiction-specific disclaimer."})]})},{id:"audit",title:"11. Audit Trail & Data Lineage",content:e.jsxs("div",{className:"space-y-3",children:[e.jsx("p",{children:"Every report carries a full audit object containing: prompt version (Meridian v2.4), Python model versions for each of the 12 modules, data quality scores per source, circuit breakers activated during generation, and fallbacks used."}),e.jsx("p",{children:"Data lineage is traceable from the final signal back to every raw data point used. The audit object is accessible via the API and displayed in the report footer. Report IDs are UUID4-based, globally unique, and bound to the specific payload that generated them — re-running with the same payload but a different Claude temperature would produce a new report_id."}),e.jsx("p",{children:"Historical audit records are retained for 7 years for Institutional clients in compliance with MiFID II record-keeping requirements."})]})}];function x({lightMode:i}){const t=i?"#111827":"#F9FAFB",a=i?"#6B7280":"#9CA3AF";return e.jsx("div",{className:"mx-auto max-w-5xl",children:e.jsxs("section",{className:"bis-page-shell px-6 py-8 md:px-10 md:py-10",children:[e.jsxs(n.div,{initial:{opacity:0,y:20},animate:{opacity:1,y:0},className:"mb-10",children:[e.jsx("div",{className:"bis-eyebrow mb-4",children:"Methodology Documentation · Meridian v2.4"}),e.jsx("h1",{className:"text-4xl font-bold tracking-tight mb-4",style:{color:t},children:"How Quantus Works"}),e.jsx("p",{className:"text-lg leading-relaxed",style:{color:a},children:"Plain-English documentation of the models, data sources, and analytical framework behind every Quantus report. Written for portfolio managers and executives — no raw code, no jargon."}),e.jsx("div",{className:"bis-note mt-5 p-4 text-sm text-amber-700",children:"⚠️ Quantus reports are for informational purposes only and do not constitute investment advice. Past signal performance does not guarantee future results."})]}),e.jsx(n.div,{initial:{opacity:0},animate:{opacity:1},transition:{delay:.15},children:u.map(s=>e.jsx(h,{section:s,lightMode:i},s.id))}),e.jsxs("div",{className:"mt-12 border-t pt-8 text-center text-xs",style:{borderColor:i?"#E5E7EB":"#1A1A1A",color:"#6B7280"},children:[e.jsx("p",{children:"Quantus Research Solutions · BI Solutions Group (bisolutions.group)"}),e.jsx("p",{className:"mt-1",children:"Powered by Meridian v2.4 · Model accuracy audited quarterly · Last updated Feb 2026"})]})]})})}export{x as Methodology};
